12â†’// formatSearchResults renders a search result set as markdown text.
13â†’func formatSearchResults(result *item.SearchResult) string {
14â†’	if len(result.Items) == 0 {
15â†’		return "No items found."
16â†’	}
17â†’
18â†’	var b strings.Builder
19â†’	fmt.Fprintf(&b, "Found %d item(s):\n\n", result.Total)
20â†’
21â†’	for _, it := range result.Items {
22â†’		b.WriteString(formatItemSummary(it))
23â†’		b.WriteString("\n")
24â†’	}
25â†’
26â†’	if result.HasMore {
27â†’		b.WriteString("_(more results available â€” increase limit or refine query)_\n")
28â†’	}
29â†’
30â†’	return b.String()
31â†’}
