33â†’// formatItemSummary renders a single item as a compact summary line.
34â†’func formatItemSummary(it *item.Item) string {
35â†’	var b strings.Builder
36â†’
37â†’	title := it.ID.String()
38â†’	if it.Title != nil && *it.Title != "" {
39â†’		title = *it.Title
40â†’	}
41â†’
42â†’	fmt.Fprintf(&b, "- **%s** [%s] (id: %s)", title, it.Type, it.ID)
43â†’
44â†’	if len(it.Tags) > 0 {
45â†’		fmt.Fprintf(&b, " tags: %s", strings.Join(it.Tags, ", "))
46â†’	}
47â†’
48â†’	if it.ContentText != nil && *it.ContentText != "" {
49â†’		snippet := *it.ContentText
50â†’		if len(snippet) > maxSnippetLen {
51â†’			snippet = snippet[:maxSnippetLen] + "..."
52â†’		}
53â†’		fmt.Fprintf(&b, "\n  > %s", strings.ReplaceAll(snippet, "\n", "\n  > "))
54â†’	}
55â†’
56â†’	b.WriteString("\n")
57â†’	return b.String()
58â†’}
