60â†’// formatItem renders a full item as detailed markdown.
61â†’func formatItem(it *item.Item) string {
62â†’	var b strings.Builder
63â†’
64â†’	title := it.ID.String()
65â†’	if it.Title != nil && *it.Title != "" {
66â†’		title = *it.Title
67â†’	}
68â†’
69â†’	fmt.Fprintf(&b, "# %s\n\n", title)
70â†’	fmt.Fprintf(&b, "- **ID:** %s\n", it.ID)
71â†’	fmt.Fprintf(&b, "- **Type:** %s\n", it.Type)
72â†’	fmt.Fprintf(&b, "- **Status:** %s\n", it.Status)
73â†’	fmt.Fprintf(&b, "- **Sensitivity:** %s\n", it.Sensitivity)
74â†’	fmt.Fprintf(&b, "- **Source:** %s\n", it.Source)
75â†’	fmt.Fprintf(&b, "- **Captured:** %s\n", it.CapturedAt.Format("2006-01-02 15:04:05"))
76â†’
77â†’	if len(it.Tags) > 0 {
78â†’		fmt.Fprintf(&b, "- **Tags:** %s\n", strings.Join(it.Tags, ", "))
79â†’	}
80â†’
81â†’	if it.SourceURL != nil && *it.SourceURL != "" {
82â†’		fmt.Fprintf(&b, "- **URL:** %s\n", *it.SourceURL)
83â†’	}
84â†’
85â†’	if it.ContentURL != nil && *it.ContentURL != "" {
86â†’		fmt.Fprintf(&b, "- **Content URL:** %s\n", *it.ContentURL)
87â†’	}
88â†’
89â†’	if it.ContentText != nil && *it.ContentText != "" {
90â†’		fmt.Fprintf(&b, "\n## Content\n\n%s\n", *it.ContentText)
91â†’	}
